	if err != nil {
		return &RuntimeError{Err: err}
	}
	defer file.Close()

	tarReader := tar.NewReader(file)

	for {
		header, err := tarReader.Next()
		if err == io.EOF {
			break
		}
		if err != nil {
			return &RuntimeError{Err: err}
		}

		name := header.Name
		if name == "" {
			return &ValueError{}
		}

		if filepath.IsAbs(name) {
			return &ValueError{}
		}

		cleanName := filepath.Clean(name)
		if cleanName == ".." {
			return &ValueError{}
		}
		if strings.HasPrefix(cleanName, ".."+string(filepath.Separator)) {
			return &ValueError{}
		}
		parts := strings.Split(cleanName, string(filepath.Separator))
		for _, part := range parts {
			if part == ".." {
				return &ValueError{}
			}
		}

		targetPath := filepath.Join("/tmp", cleanName)

		switch header.Typeflag {
		case tar.TypeDir:
			if err := os.MkdirAll(targetPath, os.FileMode(header.Mode)); err != nil {
				return &RuntimeError{Err: err}
			}
		case tar.TypeReg, tar.TypeRegA:
			outFile, err := os.OpenFile(targetPath, os.O_CREATE|os.O_WRONLY, os.FileMode(header.Mode))
			if err != nil {
				return &RuntimeError{Err: err}
			}
			if _, err := io.Copy(outFile, tarReader); err != nil {
				outFile.Close()
				return &RuntimeError{Err: err}
			}
			outFile.Close()
		case tar.TypeSymlink:
			if err := os.Symlink(header.Linkname, targetPath); err != nil {
				return &RuntimeError{Err: err}
			}
		case tar.TypeLink:
			linkPath := filepath.Join("/tmp", filepath.Clean(header.Linkname))
			if err := os.Link(linkPath, targetPath); err != nil {
				return &RuntimeError{Err: err}
			}
		}
	}

	return nil
}

