		return nil
	}

	switch node := n.(type) {
	case *ast.Ident:
		v.err = errors.New("identifiers not allowed")
		return nil
	case *ast.BasicLit:
		if node.Kind != token.INT && node.Kind != token.FLOAT {
			v.err = errors.New("only numeric literals allowed")
			return nil
		}
	case *ast.BinaryExpr:
		switch node.Op {
		case token.ADD, token.SUB, token.MUL, token.QUO, token.REM:
		default:
			v.err = fmt.Errorf("operator %s not allowed", node.Op)
			return nil
		}
	case *ast.UnaryExpr:
		switch node.Op {
		case token.ADD, token.SUB:
		default:
			v.err = fmt.Errorf("unary operator %s not allowed", node.Op)
			return nil
		}
	case *ast.ParenExpr:
		// Always allowed
	case *ast.CallExpr:
		v.err = errors.New("function calls not allowed")
		return nil
	}

	return v
